// Return the latest detections stored in global context
// Try multiple possible variable names
let detections = global.get('latestDetections') || global.get('latest_detections') || flow.get('latestDetections') || [];
msg.payload = detections;
return msg;

// Parse YOLO detections and store for HTTP access
let detections = [];

if (msg.payload && msg.payload.boxes) {
    // Standard YOLO output format
    for (let box of msg.payload.boxes) {
        detections.push({
            class: box.class || 'person',
            x1: Math.round(box.x1 || box.xmin || 0),
            y1: Math.round(box.y1 || box.ymin || 0),
            x2: Math.round(box.x2 || box.xmax || 0),
            y2: Math.round(box.y2 || box.ymax || 0),
            confidence: box.confidence || box.score || 0.5,
            timestamp: Date.now()
        });
    }
} else if (Array.isArray(msg.payload)) {
    // Array format
    for (let det of msg.payload) {
        if (det.class === 'person' || det.label === 'person' || det.name === 'person') {
            detections.push({
                class: 'person',
                x1: Math.round(det.x1 || det.xmin || det.bbox?.[0] || 0),
                y1: Math.round(det.y1 || det.ymin || det.bbox?.[1] || 0),
                x2: Math.round(det.x2 || det.xmax || det.bbox?.[2] || 0),
                y2: Math.round(det.y2 || det.ymax || det.bbox?.[3] || 0),
                confidence: det.confidence || det.score || 0.5,
                timestamp: Date.now()
            });
        }
    }
}

// Store in flow context
flow.set('latest_detections', detections);

// Pass through for debugging
msg.stored_count = detections.length;
return msg;
